===backend/src/InventoryFlow.Application/Features/Products/ProductHandlers.cs
     1	using InventoryFlow.Domain.Entities;
     2	using MediatR;
     3	
     4	namespace InventoryFlow.Application.Features.Products;
     5	
     6	/// <summary>Handles product creation.</summary>
     7	public sealed class CreateProductHandler(IProductCatalog catalog, TimeProvider timeProvider) : IRequestHandler<CreateProductCommand, ProductResponse>
     8	{
     9	    /// <inheritdoc />
    10	    public async Task<ProductResponse> Handle(CreateProductCommand request, CancellationToken cancellationToken)
    11	    {
    12	        var product = new Product(Guid.NewGuid(), request.WorkspaceId, request.Name, request.Sku, timeProvider.GetUtcNow());
    13	        return ProductResponse.From(await catalog.CreateAsync(product, cancellationToken));
    14	    }
    15	}
    16	/// <summary>Handles active-product listing.</summary>
    17	public sealed class ListProductsHandler(IProductCatalog catalog) : IRequestHandler<ListProductsQuery, IReadOnlyList<ProductResponse>>
    18	{
    19	    /// <inheritdoc />
    20	    public async Task<IReadOnlyList<ProductResponse>> Handle(ListProductsQuery request, CancellationToken cancellationToken) =>
    21	        (await catalog.ListActiveAsync(request.WorkspaceId, cancellationToken)).Select(ProductResponse.From).ToArray();
    22	}
    23	/// <summary>Handles idempotent product archive.</summary>
    24	public sealed class ArchiveProductHandler(IProductCatalog catalog, TimeProvider timeProvider) : IRequestHandler<ArchiveProductCommand, bool>
    25	{
    26	    /// <inheritdoc />
    27	    public async Task<bool> Handle(ArchiveProductCommand request, CancellationToken cancellationToken)
    28	    {
    29	        var product = await catalog.FindAsync(request.WorkspaceId, request.ProductId, cancellationToken);
    30	        if (product is null) return false;
    31	        product.Archive(timeProvider.GetUtcNow());
    32	        await catalog.SaveChangesAsync(cancellationToken);
    33	        return true;
    34	    }
    35	}
