 1	using InventoryFlow.Infrastructure.Persistence;
 2	using Microsoft.AspNetCore.Hosting;
 3	using Microsoft.AspNetCore.Mvc.Testing;
 4	using Microsoft.Data.SqlClient;
 5	using Microsoft.EntityFrameworkCore;
 6	using Microsoft.Extensions.DependencyInjection;
 7	using Testcontainers.MsSql;
 8	
 9	namespace InventoryFlow.IntegrationTests.Api;
10	
11	/// <summary>
12	/// Provides an API host backed by an isolated, migrated SQL Server database.
13	/// </summary>
14	public sealed class AuthenticatedApiFixture : IAsyncLifetime
15	{
16	    private const string ConnectionStringEnvironmentVariable =
17	        "ConnectionStrings__InventoryFlowDatabase";
18	    private const string SigningKeyEnvironmentVariable = "Jwt__SigningKey";
19	    private const string IssuerEnvironmentVariable = "Jwt__Issuer";
20	    private const string AudienceEnvironmentVariable = "Jwt__Audience";
21	
22	    private readonly MsSqlContainer _sqlServer = new MsSqlBuilder(
23	        "mcr.microsoft.com/mssql/server:2022-CU14-ubuntu-22.04").Build();
24	    private readonly string? _originalConnectionString = Environment.GetEnvironmentVariable(
25	        ConnectionStringEnvironmentVariable);
26	    private readonly string? _originalSigningKey = Environment.GetEnvironmentVariable(
27	        SigningKeyEnvironmentVariable);
28	    private readonly string? _originalIssuer = Environment.GetEnvironmentVariable(
29	        IssuerEnvironmentVariable);
30	    private readonly string? _originalAudience = Environment.GetEnvironmentVariable(
31	        AudienceEnvironmentVariable);
32	
33	    /// <summary>
34	    /// Gets the hosted API factory.
35	    /// </summary>
36	    public WebApplicationFactory<Program> Factory { get; private set; } = null!;
37	
38	    /// <inheritdoc />
39	    public async Task InitializeAsync()
40	    {
41	        await _sqlServer.StartAsync();
42	
43	        var databaseName = $"InventoryFlowTests_{Guid.NewGuid():N}";
44	        await using (var connection = new SqlConnection(_sqlServer.GetConnectionString()))
45	        {
46	            await connection.OpenAsync();
47	            await using var command = connection.CreateCommand();
48	            command.CommandText = $"CREATE DATABASE [{databaseName}]";
49	            await command.ExecuteNonQueryAsync();
50	        }
51	
52	        var connectionStringBuilder = new SqlConnectionStringBuilder(_sqlServer.GetConnectionString())
53	        {
54	            InitialCatalog = databaseName,
55	        };
56	        Environment.SetEnvironmentVariable(
57	            ConnectionStringEnvironmentVariable,
58	            connectionStringBuilder.ConnectionString);
59	        Environment.SetEnvironmentVariable(
60	            SigningKeyEnvironmentVariable,
61	            "test-signing-key-that-is-at-least-thirty-two-bytes-long");
62	        Environment.SetEnvironmentVariable(IssuerEnvironmentVariable, "InventoryFlow.Test");
63	        Environment.SetEnvironmentVariable(AudienceEnvironmentVariable, "InventoryFlow.Test.Web");
64	        Factory = new AuthenticatedApiFactory();
65	
66	        await using var scope = Factory.Services.CreateAsyncScope();
67	        var dbContext = scope.ServiceProvider.GetRequiredService<ApplicationDbContext>();
68	        await dbContext.Database.MigrateAsync();
69	    }
70	
71	    /// <inheritdoc />
72	    public async Task DisposeAsync()
73	    {
74	        Factory?.Dispose();
75	        Environment.SetEnvironmentVariable(
76	            ConnectionStringEnvironmentVariable,
77	            _originalConnectionString);
78	        Environment.SetEnvironmentVariable(SigningKeyEnvironmentVariable, _originalSigningKey);
79	        Environment.SetEnvironmentVariable(IssuerEnvironmentVariable, _originalIssuer);
80	        Environment.SetEnvironmentVariable(AudienceEnvironmentVariable, _originalAudience);
81	        await _sqlServer.DisposeAsync();
82	    }
83	
84	    private sealed class AuthenticatedApiFactory : WebApplicationFactory<Program>
85	    {
86	        /// <inheritdoc />
